package com.sixgroup.refit.devkafka;

import org.springframework.boot.autoconfigure.AutoConfiguration;
import org.springframework.boot.autoconfigure.condition.ConditionalOnMissingBean;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.boot.web.client.RestTemplateBuilder;
import org.springframework.context.annotation.Bean;
import org.springframework.http.client.SimpleClientHttpRequestFactory;
import org.springframework.web.client.RestTemplate;

import javax.net.ssl.HttpsURLConnection;
import javax.net.ssl.SSLContext;
import javax.net.ssl.TrustManager;
import javax.net.ssl.X509TrustManager;
import java.security.SecureRandom;
import java.security.cert.X509Certificate;

import lombok.extern.slf4j.Slf4j;

@AutoConfiguration
@EnableConfigurationProperties({SchemaRegistryProperties.class})
@Slf4j
public class LibraryAutoConfiguration {

    /**
     * SINGLE RestTemplate exposed by the library.
     * Conditionally configures for insecure SSL if enabled in properties.
     */
    @Bean(name = "libraryRestTemplate")
    @ConditionalOnMissingBean(name = "libraryRestTemplate")
    public RestTemplate libreriaRestTemplate(RestTemplateBuilder builder, SchemaRegistryProperties schemaRegistryProperties) {
        if (schemaRegistryProperties.isIgnoreSsl()) {
            log.warn("⚠️  SSL verification disabled for libraryRestTemplate (DEV/QA only, controlled by library.schema.ignoreSsl=true)");
            try {
                TrustManager[] trustAll = new TrustManager[]{
                        new X509TrustManager() {
                            public X509Certificate[] getAcceptedIssuers() { return new X509Certificate[0]; }
                            public void checkClientTrusted(X509Certificate[] c, String a) {}
                            public void checkServerTrusted(X509Certificate[] c, String a) {}
                        }
                };
                SSLContext ctx = SSLContext.getInstance("TLS");
                ctx.init(null, trustAll, new SecureRandom());

                SimpleClientHttpRequestFactory requestFactory = new SimpleClientHttpRequestFactory();
                requestFactory.setBufferRequestBody(false); // Important for large payloads
                HttpsURLConnection.setDefaultSSLSocketFactory(ctx.getSocketFactory()); // This affects global HttpsURLConnection
                HttpsURLConnection.setDefaultHostnameVerifier((h, s) -> true); // This affects global HttpsURLConnection

                // For RestTemplate, we need to set the SSLContext on the underlying HTTP client
                // SimpleClientHttpRequestFactory uses HttpURLConnection, which respects global defaults set above.
                // For more advanced HTTP clients (like Apache HttpClient or OkHttp), specific configuration would be needed.
                // Given SimpleClientHttpRequestFactory is used, the global settings are sufficient for it.
                return builder.requestFactory(() -> requestFactory).build();

            } catch (Exception e) {
                log.error("❌ Error configuring insecure SSL for RestTemplate: {}", e.getMessage());
                // Fallback to default builder if SSL configuration fails
                return builder.build();
            }
        }
        return builder.build();
    }

    /**
     * Schema Registry client service.
     */
    @Bean
    @ConditionalOnMissingBean
    @ConditionalOnProperty(prefix = "library.schema", name = "enabled", havingValue = "true", matchIfMissing = true)
    public SchemaRegistryClientService schemaRegistryClientService(
            RestTemplate libraryRestTemplate, // Inject the configured RestTemplate
            SchemaRegistryProperties schemaRegistryProperties) { // Inject properties
        return new SchemaRegistryClientService(libraryRestTemplate, schemaRegistryProperties);
    }

    /**
     * Schema downloader from Schema Registry.
     */
    @Bean
    @ConditionalOnMissingBean
    @ConditionalOnProperty(prefix = "library.schema", name = "enabled", havingValue = "true", matchIfMissing = true)
    public SchemaDownload schemaDownload(SchemaRegistryClientService schemaRegistryClientService,
                                         SchemaRegistryProperties schemaRegistryProperties) { // Inject properties
        return new SchemaDownload(schemaRegistryClientService, schemaRegistryProperties);
    }

    /**
     * Generic runner for sending messages.
     */
    @Bean
    @ConditionalOnMissingBean
    @ConditionalOnProperty(prefix = "library.runner", name = "enabled", havingValue = "true", matchIfMissing = true)
    public GenericRunnerBean genericRunnerBean(SchemaDownload schemaDownload) {
        return new GenericRunnerBean(schemaDownload);
    }

    /**
     * REST Proxy client (for listing topics, sending messages, etc.).
     */
    @Bean
    @ConditionalOnMissingBean
    @ConditionalOnProperty(prefix = "library.restproxy", name = "enabled", havingValue = "true", matchIfMissing = true)
    public KafkaRestProxyClientService kafkaRestProxyClientService(SchemaRegistryProperties schemaRegistryProperties) { // Inject properties
        return new KafkaRestProxyClientService(schemaRegistryProperties);
    }
}

package com.sixgroup.refit.devkafka;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import lombok.extern.slf4j.Slf4j;

import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.util.Base64; // Added for basic auth

/**
 * Client for the Schema Registry. SSL verification can be ignored via configuration (QA/DEV only).
 */
@Service
@Slf4j
public class SchemaRegistryClientService {

    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;
    private final SchemaRegistryProperties schemaRegistryProperties; // Inject properties

    public SchemaRegistryClientService(RestTemplate restTemplate, SchemaRegistryProperties schemaRegistryProperties) {
        this.restTemplate = restTemplate;
        this.objectMapper = new ObjectMapper();
        this.schemaRegistryProperties = schemaRegistryProperties;
        // No need for CustomHeaderInterceptor here, headers should be handled by RestTemplate or specific requests.
    }

    /**
     * Downloads the latest schema of a subject.
     *
     * @param subject Registry subject.
     * @return Schema as a String (JSON raw).
     */
    public String getLatestSchema(String schemaRegistry, String subject, String urlPrefix) {
        String url = schemaRegistry + subject + urlPrefix;
        log.info("🌍 Searching for schema at URL: {}", url);

        try {
            // Add Basic Authentication header if configured
            if (schemaRegistryProperties.getBasicTokenBase64() != null && !schemaRegistryProperties.getBasicTokenBase64().isBlank()) {
                restTemplate.getInterceptors().add((request, body, execution) -> {
                    request.getHeaders().add("Authorization", "Basic " + schemaRegistryProperties.getBasicTokenBase64());
                    return execution.execute(request, body);
                });
            } else if (schemaRegistryProperties.getUser() != null && !schemaRegistryProperties.getUser().isBlank() &&
                       schemaRegistryProperties.getPass() != null && !schemaRegistryProperties.getPass().isBlank()) {
                String auth = schemaRegistryProperties.getUser() + ":" + schemaRegistryProperties.getPass();
                String encodedAuth = Base64.getEncoder().encodeToString(auth.getBytes());
                restTemplate.getInterceptors().add((request, body, execution) -> {
                    request.getHeaders().add("Authorization", "Basic " + encodedAuth);
                    return execution.execute(request, body);
                });
            }

            ResponseEntity<String> response = restTemplate.getForEntity(url, String.class);
            JsonNode root = objectMapper.readTree(response.getBody());

            String schema = root.get("schema").asText();
            log.info("✅ Schema obtained for [{}]", subject);
            return schema;

        } catch (Exception e) {
            log.error("❌ Error obtaining schema [{}]: {}", subject, e.getMessage());
            throw new RuntimeException("Schema registry fetch failed", e);
        }
    }

    // Removed disableSSLVerification() and CustomHeaderInterceptor.
    // SSL configuration is now handled by LibraryAutoConfiguration based on schemaRegistryProperties.isIgnoreSsl().
}

package com.sixgroup.refit.devkafka;

import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import javax.net.ssl.SSLContext;
import javax.net.ssl.TrustManager;
import javax.net.ssl.X509TrustManager;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.security.SecureRandom;
import java.security.cert.X509Certificate;
import java.util.Arrays;
import java.util.List;

@Service
@Slf4j
public class KafkaRestProxyClientService {

    private final ObjectMapper mapper = new ObjectMapper();
    private final SchemaRegistryProperties schemaRegistryProperties; // Inject properties

    public KafkaRestProxyClientService(SchemaRegistryProperties schemaRegistryProperties) {
        this.schemaRegistryProperties = schemaRegistryProperties;
    }

    /**
     * Lists all available topics from the REST Proxy.
     * SSL verification can be ignored via configuration (QA/DEV only).
     */
    public List<String> listTopics(String restProxyUrl) {
        String endpoint = restProxyUrl.endsWith("/topics") ? restProxyUrl : restProxyUrl + "/topics";
        log.info("🌍 Requesting topic list from: {}", endpoint);

        HttpClient client;
        HttpRequest request;

        try {
            HttpClient.Builder clientBuilder = HttpClient.newBuilder();

            if (schemaRegistryProperties.isIgnoreSsl()) {
                log.warn("⚠️  SSL verification disabled for KafkaRestProxyClientService (DEV/QA only, controlled by library.schema.ignoreSsl=true)");
                clientBuilder.sslContext(createInsecureSslContext());
            }

            client = clientBuilder.build();

            request = HttpRequest.newBuilder()
                    .uri(URI.create(endpoint))
                    .header("Accept", "application/json")
                    .GET()
                    .build();
        } catch (Exception e) {
            log.error("❌ Error configuring HttpClient/SSL: {}", e.getMessage());
            throw new RuntimeException("Error configuring HttpClient", e);
        }

        try {
            HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
            int status = response.statusCode();

            if (status != 200) {
                log.error("⚠️ HTTP error {} when obtaining topics: {}", status, response.body());
                throw new RuntimeException("HTTP error " + status + ": " + response.body());
            }

            String body = response.body();
            log.info("✅ Topics JSON received: {}", body);

            return Arrays.asList(mapper.readValue(body, String[].class));

        } catch (IOException | InterruptedException e) {
            log.error("❌ Error obtaining topic list: {}", e.getMessage(), e);
            throw new RuntimeException("Error obtaining topic list", e);
        }
    }

    /*───────────────────────────────────────────────────────────────*/
    /* SSL ignored (testing only) - now conditional */
    /*───────────────────────────────────────────────────────────────*/
    private static SSLContext createInsecureSslContext() throws Exception {
        TrustManager[] trustAllCerts = new TrustManager[]{
                new X509TrustManager() {
                    public X509Certificate[] getAcceptedIssuers() {
                        return new X509Certificate[0];
                    }
                    public void checkClientTrusted(X509Certificate[] c, String a) {}
                    public void checkServerTrusted(X509Certificate[] c, String a) {}
                }
        };

        SSLContext ctx = SSLContext.getInstance("TLS");
        ctx.init(null, trustAllCerts, new SecureRandom());
        return ctx;
    }
}

package com.sixgroup.refit.devkafka;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;

import com.sixgroup.refit.devkafka.exception.ErrorMessageException;

import lombok.extern.slf4j.Slf4j;

import org.springframework.stereotype.Component;

import javax.net.ssl.SSLContext;
import javax.net.ssl.TrustManager;
import javax.net.ssl.X509TrustManager;

import java.io.File;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.security.cert.X509Certificate;

@Component
@Slf4j
public class SchemaDownload {

    private static final ObjectMapper mapper = new ObjectMapper();
    private final SchemaRegistryClientService schemaRegistryDownloader;
    private final SchemaRegistryProperties schemaRegistryProperties; // Inject properties

    public SchemaDownload(SchemaRegistryClientService schemaRegistryDownloader, SchemaRegistryProperties schemaRegistryProperties) {
        this.schemaRegistryDownloader = schemaRegistryDownloader;
        this.schemaRegistryProperties = schemaRegistryProperties;
    }

    public void exportAndSendAvroMessages(String keyPayloadFile, String valuePayloadFile, String schemaRegistry, String topicName, String restProxyUrl, String urlPrefix)
            throws ErrorMessageException {
        log.info("✅ DevUK109TargetComponent loaded. Ready to execute Avro message sending API.");
        log.info("📁 File key: {}", keyPayloadFile);
        log.info("📁 File value: {}", valuePayloadFile);
        log.info("📁 Schema Registry: {}", schemaRegistry);
        log.info("📝 Topic name  : {}", topicName);
        log.info("📝 REST Proxy  : {}", restProxyUrl);
        log.info("📝 URL Prefix  : {}", urlPrefix);

        sendAvroMessageWithSchema(keyPayloadFile, valuePayloadFile, schemaRegistry, topicName, restProxyUrl, urlPrefix);
    }

    private void sendAvroMessageWithSchema(String keyFilePath, String valueFilePath, String schemaRegistry, String topicName, String restProxyUrl, String urlPrefix)
            throws ErrorMessageException {
        String fullRestProxyUrl = restProxyUrl + "/" + topicName;

        JsonNode keyPayload = readJsonFile(keyFilePath, "KEY");
        JsonNode valuePayload = readJsonFile(valueFilePath, "VALUE");

        String keySchema = schemaRegistryDownloader.getLatestSchema(schemaRegistry, topicName + "-key", urlPrefix);
        log.info("✅ KEY Schema downloaded:\n{}", keySchema);

        String valueSchema = schemaRegistryDownloader.getLatestSchema(schemaRegistry, topicName + "-value", urlPrefix);
        log.info("✅ VALUE Schema downloaded:\n{}", valueSchema);

        ObjectNode payload = mapper.createObjectNode();
        payload.put("key_schema", keySchema);
        payload.put("value_schema", valueSchema);

        ArrayNode records = mapper.createArrayNode();
        ObjectNode recordNode = mapper.createObjectNode();
        recordNode.set("key", keyPayload);
        recordNode.set("value", valuePayload);
        records.add(recordNode);

        payload.set("records", records);

        try {
            String jsonPayload = mapper.writerWithDefaultPrettyPrinter().writeValueAsString(payload);
            log.info("📨 Payload sent to REST Proxy:\n{}", jsonPayload);

            HttpClient.Builder httpClientBuilder = HttpClient.newBuilder();

            if (schemaRegistryProperties.isIgnoreSsl()) {
                log.warn("⚠️  SSL verification disabled for SchemaDownload (DEV/QA only, controlled by library.schema.ignoreSsl=true)");
                httpClientBuilder.sslContext(createInsecureSslContext());
            }

            HttpClient httpClient = httpClientBuilder.build();

            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(fullRestProxyUrl))
                    .header("Content-Type", "application/vnd.kafka.avro.v2+json")
                    .header("Accept", "application/vnd.kafka.v2+json, application/vnd.kafka+json, application/json")
                    .POST(HttpRequest.BodyPublishers.ofString(jsonPayload, StandardCharsets.UTF_8))
                    .build();

            log.info("🚀 Sending to REST Proxy: {}", fullRestProxyUrl);

            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

            if (response.statusCode() == 200) {
                log.info("✅ Message sent successfully");
                log.info("↩️ Response ({}): {}", response.statusCode(), response.body());
            } else {
                log.error("⚠️ Error sending message. Code {}", response.statusCode());
                log.error("⚠️ Response: {}", response.body());
                throw new ErrorMessageException("REST Proxy error: " + response.statusCode());
            }
        } catch (IOException | InterruptedException e) {
            log.error("❌ Error sending message", e);
            throw new ErrorMessageException("Error sending REST Proxy request: " + e.getMessage());
        } catch (Exception e) {
            log.error("❌ Unexpected error", e);
            throw new ErrorMessageException("Unexpected error: " + e.getMessage());
        }
    }

    private JsonNode readJsonFile(String filePath, String type) throws ErrorMessageException {
        log.info("⏱️ Loading {} from: {}", type, filePath);
        try {
            File file = new File(filePath);
            // Path Traversal Vulnerability Fix: Canonicalize path to prevent directory traversal
            String canonicalPath = file.getCanonicalPath();
            String currentDir = new File(".").getCanonicalPath(); // Or a specific base directory

            // For a dev tool, we might allow reading from anywhere, but log a warning if outside current dir
            // For production, this should be restricted to a specific safe directory.
            if (!canonicalPath.startsWith(currentDir)) {
                log.warn("⚠️  Attempting to read file outside current working directory: {}", canonicalPath);
                // Depending on security policy, this could be an error:
                // throw new ErrorMessageException("File path outside allowed directory: " + filePath);
            }

            if (!file.exists()) {
                throw new ErrorMessageException("File not found: " + filePath);
            }
            if (!file.isFile()) {
                throw new ErrorMessageException("Path is not a file: " + filePath);
            }

            return mapper.readTree(file);
        } catch (IOException e) {
            log.error("❌ Error loading {} payload from {}: {}", type, filePath, e.getMessage());
            throw new ErrorMessageException("Error loading " + type + " payload: " + e.getMessage());
        }
    }

    /**
     * FOR TESTING ONLY: Creates an SSLContext that does not validate certificates.
     * Now called conditionally based on configuration.
     */
    private static SSLContext createInsecureSslContext() throws Exception {
        TrustManager[] trustAllCerts = new TrustManager[]{
                new X509TrustManager() {
                    public X509Certificate[] getAcceptedIssuers() {
                        return new X509Certificate[0];
                    }

                    public void checkClientTrusted(X509Certificate[] c, String a) {
                    }

                    public void checkServerTrusted(X509Certificate[] c, String a) {
                    }
                }
        };
        SSLContext ctx = SSLContext.getInstance("TLS");
        ctx.init(null, trustAllCerts, new SecureRandom());
        return ctx;
    }
}

package com.sixgroup.refit.devkafka;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import com.sixgroup.refit.devkafka.exception.ErrorMessageException;
import okhttp3.mockwebserver.MockResponse;
import okhttp3.mockwebserver.MockWebServer;
import org.junit.jupiter.api.*;
import org.mockito.Mockito;

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

class SchemaDownloadTest {

    private MockWebServer mockWebServer;
    private SchemaRegistryClientService mockRegistry;
    private SchemaDownload schemaDownload;

    private File keyFile;
    private File valueFile;
    private static final ObjectMapper mapper = new ObjectMapper();

    @BeforeEach
    void setUp() throws IOException {
        // Simulated REST Proxy server
        mockWebServer = new MockWebServer();
        mockWebServer.start();

        // Mock of the Schema Registry service
        mockRegistry = Mockito.mock(SchemaRegistryClientService.class);
        schemaDownload = new SchemaDownload(mockRegistry);

        // Temporary payload files
        keyFile = File.createTempFile("key", ".json");
        valueFile = File.createTempFile("value", ".json");

        try (FileWriter fw = new FileWriter(keyFile)) {
            fw.write("{\"id\": 1}");
        }
        try (FileWriter fw = new FileWriter(valueFile)) {
            fw.write("{\"name\": \"test\"}");
        }
    }

    @AfterEach
    void tearDown() throws IOException {
        mockWebServer.shutdown();
        keyFile.delete();
        valueFile.delete();
    }

    @Test
    @DisplayName("✅ Correctly sends an Avro message to the REST Proxy")
    void testExportAndSendAvroMessages_success() throws Exception {
        // 1️⃣ Mock of the schema registry
        when(mockRegistry.getLatestSchema(any(), eq("test-topic-key"), any()))
                .thenReturn("{\"type\":\"string\"}");
        when(mockRegistry.getLatestSchema(any(), eq("test-topic-value"), any()))
                .thenReturn("{\"type\":\"int\"}");

        // 2️⃣ Simulated REST Proxy response (200 OK)
        mockWebServer.enqueue(new MockResponse()
                .setResponseCode(200)
                .setBody("{\"offsets\": [{\"partition\": 0, \"offset\": 1}]}"));

        String baseUrl = mockWebServer.url("/topics").toString();

        // 3️⃣ Execute the method
        schemaDownload.exportAndSendAvroMessages(
                keyFile.getAbsolutePath(),
                valueFile.getAbsolutePath(),
                "http://schema-registry.dev",
                "test-topic",
                baseUrl,
                "http://prefix/"
        );

        // 4️⃣ Verify that the expected mock methods were called
        verify(mockRegistry, times(1))
                .getLatestSchema(any(), eq("test-topic-key"), any());
        verify(mockRegistry, times(1))
                .getLatestSchema(any(), eq("test-topic-value"), any());

        // 5️⃣ Analyze the request received by the MockWebServer
        var recorded = mockWebServer.takeRequest();
        String body = recorded.getBody().readUtf8();

        assertEquals("POST", recorded.getMethod());
        assertTrue(body.contains("key_schema"), "Must contain key_schema");
        assertTrue(body.contains("records"), "Must contain records");

        // 6️⃣ Validate the sent JSON content
        JsonNode payload = mapper.readTree(body);
        assertEquals("{\"type\":\"string\"}", payload.get("key_schema").asText());
        assertEquals("{\"type\":\"int\"}", payload.get("value_schema").asText());

        JsonNode recordNode = payload.get("records").get(0);
        assertEquals(1, recordNode.get("key").get("id").asInt());
        assertEquals("test", recordNode.get("value").get("name").asText());
    }

    @Test
    @DisplayName("⚠️ Throws ErrorMessageException if the REST Proxy returns an HTTP error")
    void testExportAndSendAvroMessages_httpError() {
        when(mockRegistry.getLatestSchema(any(), anyString(), any()))
                .thenReturn("{\"type\":\"string\"}");

        mockWebServer.enqueue(new MockResponse()
                .setResponseCode(500)
                .setBody("{\"error\":\"internal server error\"}"));

        String baseUrl = mockWebServer.url("/topics").toString();

        assertThrows(ErrorMessageException.class, () -> {
            schemaDownload.exportAndSendAvroMessages(
                    keyFile.getAbsolutePath(),
                    valueFile.getAbsolutePath(),
                    "http://schema-registry.dev",
                    "test-topic",
                    baseUrl,
                    "http://prefix/"
            );
        });
    }

    @Test
    @DisplayName("🚫 Throws ErrorMessageException if the JSON file cannot be read")
    void testExportAndSendAvroMessages_fileError() {
        File missing = new File("nonexistent.json");

        assertThrows(ErrorMessageException.class, () -> {
            schemaDownload.exportAndSendAvroMessages(
                    missing.getAbsolutePath(),
                    missing.getAbsolutePath(),
                    "http://schema-registry.dev",
                    "test-topic",
                    "http://localhost",
                    "http://prefix/"
            );
        });
    }
}

package com.sixgroup.refit.devkafka;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.http.HttpMethod;
import org.springframework.http.MediaType;
import org.springframework.test.web.client.MockRestServiceServer;
import org.springframework.web.client.RestTemplate;

import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.*;
import static org.springframework.test.web.client.ExpectedCount.once;
import static org.springframework.test.web.client.match.MockRestRequestMatchers.*;
import static org.springframework.test.web.client.response.MockRestResponseCreators.withStatus;
import static org.springframework.http.HttpStatus.*;

class SchemaRegistryClientServiceTest {

    private SchemaRegistryClientService client;
    private MockRestServiceServer mockServer;

    @BeforeEach
    void setup() throws Exception {
        client = new SchemaRegistryClientService();

        // Access the internal RestTemplate via reflection
        Field restTemplateField = SchemaRegistryClientService.class.getDeclaredField("restTemplate");
        restTemplateField.setAccessible(true);
        RestTemplate restTemplate = (RestTemplate) restTemplateField.get(client);

        // Associate the MockRestServiceServer with the real RestTemplate of the service
        mockServer = MockRestServiceServer.createServer(restTemplate);
    }

    @Test
    @DisplayName("✅ Correctly obtains the schema from the Schema Registry")
    void testGetLatestSchema_success() throws Exception {
        String expectedSchemaJson = "{\"schema\": \"{\\\"type\\\":\\\"string\\\"}\"}";
        String baseUrl = "https://registry.dev/";
        String subject = "customer-value";
        String prefix = "/latest";

        mockServer.expect(once(), requestTo(baseUrl + subject + prefix))
                .andExpect(method(HttpMethod.GET))
                .andRespond(withStatus(OK)
                        .contentType(MediaType.APPLICATION_JSON)
                        .body(expectedSchemaJson));

        String schema = client.getLatestSchema(baseUrl, subject, prefix);

        assertEquals("{\"type\":\"string\"}", schema);
        mockServer.verify();
    }

    @Test
    @DisplayName("⚠️ Throws exception if the server returns HTTP error")
    void testGetLatestSchema_httpError() {
        String baseUrl = "https://registry.dev/";
        String subject = "order-key";
        String prefix = "/latest";

        mockServer.expect(once(), requestTo(baseUrl + subject + prefix))
                .andExpect(method(HttpMethod.GET))
                .andRespond(withStatus(INTERNAL_SERVER_ERROR)
                        .contentType(MediaType.APPLICATION_JSON)
                        .body("{\"error\": \"Internal error\"}"));

        RuntimeException ex = assertThrows(RuntimeException.class, () ->
                client.getLatestSchema(baseUrl, subject, prefix));

        assertTrue(ex.getMessage().contains("Schema registry fetch failed"));
    }

    @Test
    @DisplayName("🚫 Throws exception if the response JSON does not have 'schema' field")
    void testGetLatestSchema_invalidJson() {
        String baseUrl = "https://registry.dev/";
        String subject = "bad-value";
        String prefix = "/latest";

        mockServer.expect(once(), requestTo(baseUrl + subject + prefix))
                .andRespond(withStatus(OK)
                        .contentType(MediaType.APPLICATION_JSON)
                        .body("{\"other\":\"field\"}"));

        assertThrows(RuntimeException.class, () ->
                client.getLatestSchema(baseUrl, subject, prefix));
    }
}
